---@class LWebQuestionData
local LWebQuestionData = LxClass("LWebQuestionData", nil)

LWebQuestionData.STATUS_FAIL = -2
LWebQuestionData.STATUS_RETRY = -1
LWebQuestionData.STATUS_NONE = 0
LWebQuestionData.STATUS_REQING = 1
LWebQuestionData.STATUS_READY = 2


------------------------------------------------------------------
function LWebQuestionData:LWebQuestionData()
    self._qid = nil --问卷id

    self._status = LWebQuestionData.STATUS_NONE

    self._retryCount = 0
    self._retryDelayTimer = nil
end

function LWebQuestionData:IsDestroy()
    return self._isDestroy
end

function LWebQuestionData:InitFirstData(qid)
    self._qid = qid
end

function LWebQuestionData:Destroy()
    if self._isDestroy then return end

    self:StopRetryDelayTimer()

    table.removeall(self)
    self._isDestroy = true
end

function LWebQuestionData:GetData()
    return self._webData
end

function LWebQuestionData:StopRetryDelayTimer()
    if self._retryDelayTimer then
        LxTimer.DelayTimeStop(self._retryDelayTimer)
        self._retryDelayTimer = nil
    end
end

function LWebQuestionData:StartInitWebData()
    self:StopRetryDelayTimer()
    self._retryCount = 0
    self._status = LWebQuestionData.STATUS_NONE
    self._webData = nil


    if self:TryLoadFromFile() then
        return true
    end

    self:TryLoadFromWeb()
end

function LWebQuestionData:TryLoadFromFile()
    local documentPath = self:GetFilePath()
    local str = LFileHelper.ReadAllTextFromCache(documentPath)
    if string.isempty(str) then
        return false
    end
    local resultTbl = JSON.decode(str)
    if not resultTbl then
        return false
    end
    self._webData = resultTbl
    self._status = LWebQuestionData.STATUS_READY

    self:FormatQuestList(resultTbl)
    return true
end

function LWebQuestionData:TryLoadFromWeb()
    local webUrl = gLGameLogin:GetQuestionUrl()
    if string.isempty(webUrl) then
        printErrorN("question url is nil")
        return
    end
    local urlSuffix= string.format("%s.json",self._qid)

    local urlList = {webUrl}
    local qid = self._qid
    LxHttpHelper.DoWebRequestURL(nil,urlList, urlSuffix,function (...) self:OnActivityWebDataResult(qid,...) end, false)
end

function LWebQuestionData:GetFilePath()
    local path = string.format("%squetionaire/%s.json",CS.AppPersistentDataPath(),self._qid)
    return path
end

function LWebQuestionData:OnActivityWebDataResult(qid,ret, result,url, progress, bytes)
    if self._isDestroy then
        return
    end

    if self._qid ~= qid then
        return
    end


    if ret == CS.YXWebRet.ok then
        if string.isempty(result) then
            return
        end
        local resultTbl = JSON.decode(result)
        if not resultTbl then
            return
        end
        self._webData = resultTbl
        self._status = LWebQuestionData.STATUS_READY

        self:FormatQuestList(resultTbl)
        FireEvent(EventNames.ON_QUESTION_CONFIG_DATA,qid,self)

        local documentPath = self:GetFilePath()
        LFileHelper.WriteAllTextToCache(documentPath, result)

    elseif ret == CS.YXWebRet.Loading then

    else
        self._status = LWebQuestionData.STATUS_RETRY
        self:RetryLoaded()
    end
end


function LWebQuestionData:IsOk()
    return self._status == LWebQuestionData.STATUS_READY
end

function LWebQuestionData:RetryLoaded()
    self._retryCount = self._retryCount+1
    if self._retryCount > 1 then
        self._status = LWebQuestionData.STATUS_FAIL
        return
    end
    self:StopRetryDelayTimer()
    self._retryDelayTimer = LxTimer.DelayTimeCall(function ()
        self:TryLoadFromWeb()
    end, 5)
end

function LWebQuestionData:FormatQuestList(retTable)
    local questId = retTable.id

    local mainData = {
        id = questId
    }

    local dataTable = JSON.decode(retTable.content)
    local questionMap ={}
    for k,v in ipairs(dataTable) do
        local questData = self:FormatQuestData(mainData,v)
        questionMap[questData.id] = questData
    end

    local data =  {mainData = mainData,questionMap = questionMap}
    self._formatQuestionData = data
end

function LWebQuestionData:FormatQuestData(maindata,questdata)
    local type = questdata.type
    local data = nil
    if type == ModelQuestion.SELECT then
        data = self:FormatSelectQuestion(maindata,questdata)
    elseif type == ModelQuestion.RATE then
        data = self:FormatRateQuestion(maindata,questdata)
    elseif type == ModelQuestion.INPUT then
        data = self:FormatInputQuestion(maindata,questdata)
    elseif type == ModelQuestion.FILL then
        data = self:FormatFillQuestion(maindata,questdata)
    elseif type == ModelQuestion.SELECT_PIC then
        data = self:FormatSelectPic(maindata,questdata)
    elseif type == ModelQuestion.RATE_PIC then
        data = self:FormatRatePic(maindata,questdata)
    end

    return data
end

function LWebQuestionData:FormatSelectQuestion(maindata,questdata)

    local data = {}
    data.id = questdata.id
    data.type = ModelQuestion.SELECT
    data.necessary = questdata.necessary
    data.title = questdata.title
    data.associations = questdata.associations
    local limit = 1
    if questdata.multiply then
        limit = questdata.limitSelectCount
    end
    data.selectLimit = limit
    data.multiply = questdata.multiply
    local selectList = {}
    for k,v in ipairs(questdata.options) do
        local option = {}
        option.title = v.content
        option.name = v.name
        option.combine = v.type == 2
        option.holdText = v.placeholder
        option.limit = 40
        option.multiply = questdata.multiply
        option.questionInfo = {mainId = maindata.id,questId = questdata.id}
        option.selectLimit = limit
        table.insert(selectList,option)
    end
    data.selectList = selectList
    return data
end

function LWebQuestionData:FormatRateQuestion(maindata,questdata)
    local data = {}
    data.id = questdata.id
    data.type = ModelQuestion.RATE
    data.title = questdata.title
    data.necessary = questdata.necessary
    data.associations = questdata.associations

    local starList = {}
    for k=1,questdata.nowStarts do
        local starData = {}
        starData.index = k
        starData.questionInfo = {mainId = maindata.id,questId = questdata.id}
        table.insert(starList,starData)
    end
    data.starList = starList
    return data
end

function LWebQuestionData:FormatInputQuestion(maindata,questdata)
    local data = {}
    data.id = questdata.id
    data.type = ModelQuestion.INPUT
    data.title = questdata.title
    data.holdText = questdata.content
    data.limit = 80
    data.necessary = questdata.necessary
    data.associations = questdata.associations
    data.questionInfo = {mainId = maindata.id,questId = questdata.id}
    return data

end

function LWebQuestionData:FormatFillQuestion(maindata,questdata)
    local data = {}
    data.id = questdata.id
    data.type = ModelQuestion.FILL
    data.title = questdata.content
    data.necessary = questdata.necessary
    data.associations = questdata.associations

    local cnt = 0
    string.gsub(data.title,"___",function ()
        cnt = cnt + 1
    end)
    local fillList = {}
    for k=1,cnt do
        local data= {}
        data.index = k
        data.questionInfo = {mainId = maindata.id,questId = questdata.id}
        data.limit = 40
        table.insert(fillList,data)
    end

    data.fillList = fillList

    return data
end

function LWebQuestionData:FormatSelectPic(maindata,questdata)
    local data = {}
    data.id = questdata.id
    data.type = ModelQuestion.SELECT_PIC
    data.necessary = questdata.necessary
    data.title = questdata.title
    data.associations = questdata.associations
    local limit = 1
    if questdata.multiply then
        limit = questdata.limitSelectCount
    end
    data.selectLimit = limit
    data.multiply = questdata.multiply
    local selectList = {}
    for k,v in ipairs(questdata.options) do
        local option = {}
        option.title = v.content
        option.name = v.name
        option.combine = false
        option.holdText = v.placeholder
        option.limit = 40
        option.multiply = questdata.multiply
        option.questionInfo = {mainId = maindata.id,questId = questdata.id}
        option.selectLimit = limit
        option.picData = v.imgUrl

        table.insert(selectList,option)
    end
    data.selectList = selectList
    return data
end

function LWebQuestionData:FormatRatePic(maindata,questdata)
    local data = {}
    data.id = questdata.id
    data.type = ModelQuestion.RATE_PIC
    data.title = questdata.title
    data.necessary = questdata.necessary
    data.associations = questdata.associations

    local imgDataS = questdata.imgUrls or {}
    local starList = {}
    for k=1,questdata.nowStarts do
        local starData = {}
        starData.index = k
        starData.questionInfo = {mainId = maindata.id,questId = questdata.id}
        table.insert(starList,starData)
    end
    data.starList = starList
    data.picDataList = imgDataS
    return data
end

function LWebQuestionData:GetQuestionData(quesId)
    if not self._formatQuestionData then
        return
    end

    return self._formatQuestionData.questionMap[quesId]
end

function LWebQuestionData:GetFormatData()
    return self._formatQuestionData
end

return LWebQuestionData